import type { ReactNode } from "react";

import { Button, Card, CardContent, CardHeader, CardTitle } from "@portugal/ui";

import { cn } from "@/lib/utils";
import { RankingsTable, type RankingsRowData } from "../presentation/rankings-table";
import { SegmentedProgress, type Segment } from "../presentation/segmented-progress";

export type PlotProfileDashboardWidgetProps = {
  className?: string;
  profileCode: string;
  profileName: string;
  profileDescription: string;
  /** Tailwind gradient stops (without `bg-gradient-to-br`). */
  profileAccentClassName: string;
  profileDetailLabel?: string;
  onProfileDetail?: () => void;
  weightMixTitle?: string;
  weightSegments: readonly Segment[];
  emptyWeightsMessage?: string;
  /** Full-width block between the intro/weight row and rankings (e.g. cross-profile help). */
  afterWeightRowSlot?: ReactNode;
  rankingsRows: readonly RankingsRowData[];
  onOpenRankingsDetailPanel?: (plotId: string) => void;
  rankingsEmptyMessage?: string;
  rankingsTruncateNote?: string | null;
};

export function PlotProfileDashboardWidget({
  className,
  profileCode,
  profileName,
  profileDescription,
  profileAccentClassName,
  profileDetailLabel = "Profile detail",
  onProfileDetail,
  weightMixTitle = "Weight mix (categories)",
  weightSegments,
  emptyWeightsMessage = "No weights.",
  afterWeightRowSlot,
  rankingsRows,
  onOpenRankingsDetailPanel,
  rankingsEmptyMessage = "No plots yet. Add a plot on the Plots page to populate rankings.",
  rankingsTruncateNote,
}: PlotProfileDashboardWidgetProps) {
  return (
    <article
      className={cn(
        "flex flex-col gap-4 rounded-2xl bg-card/50 p-4 ring-1 ring-border/30",
        className,
      )}
    >
      <div className="grid gap-4 lg:grid-cols-2">
        <div
          className={cn(
            "relative flex min-h-[140px] flex-col justify-end overflow-hidden rounded-xl bg-gradient-to-br p-4 text-primary-foreground shadow-inner",
            profileAccentClassName,
          )}
        >
          <p className="text-[0.65rem] font-bold uppercase tracking-widest opacity-90">
            {profileCode}
          </p>
          <h2 className="font-display text-xl font-bold leading-tight">{profileName}</h2>
          <p className="mt-1 line-clamp-2 text-xs opacity-90">{profileDescription}</p>
          {onProfileDetail ? (
            <Button
              type="button"
              size="sm"
              variant="secondary"
              className="mt-3 w-fit"
              onClick={onProfileDetail}
            >
              {profileDetailLabel}
            </Button>
          ) : null}
        </div>

        <Card className="bg-muted/25 ring-1 ring-border/25">
          <CardHeader className="pb-2">
            <CardTitle className="font-display text-sm">{weightMixTitle}</CardTitle>
          </CardHeader>
          <CardContent>
            {weightSegments.length > 0 ? (
              <SegmentedProgress segments={weightSegments} />
            ) : (
              <p className="text-xs text-muted-foreground">{emptyWeightsMessage}</p>
            )}
          </CardContent>
        </Card>
      </div>

      {afterWeightRowSlot}

      {rankingsRows.length === 0 ? (
        <p className="text-sm text-muted-foreground">{rankingsEmptyMessage}</p>
      ) : (
        <div className="min-h-0 flex-1 space-y-2">
          <RankingsTable rows={rankingsRows} onOpenDetailPanel={onOpenRankingsDetailPanel} />
          {rankingsTruncateNote ? (
            <p className="text-xs text-muted-foreground">{rankingsTruncateNote}</p>
          ) : null}
        </div>
      )}
    </article>
  );
}

